import './Home.css';
import Footer from '../Footer';
import Contact from '../Contact';
import Banner from '../Banner';
import Work from '../Work';
import Service from '../Service';


import React, { useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next'
import { Link, Events } from 'react-scroll';

// https://emwilldesignco.com/web-design/lovella/
// <video loop="true" muted="true" preload="auto" className="videoPresent" poster="https://d15iertza0f11s.cloudfront.net/app/uploads/2019/05/16123851/Water- // flower_01.jpg" autoplay="">
//      <source type="video/mp4" src="https://d15iertza0f11s.cloudfront.net/app/uploads/2019/05/12151558/Waterflower_02.mp4">
//    </video>


function Header() {
  const scrollRef = useRef();
  const { t, i18n } = useTranslation()  
  const changeLanguage = (event) => {    
    i18n.changeLanguage( event.target.value )
  }
  
  // scroll on Header
  const onScroll = () => {
    let lastScrollTop = 0;
    let scrollTop = window.pageYOffset || scrollRef.current.scrollTop
    if (scrollTop > lastScrollTop) {
      scrollRef.current.style.opacity = 0;
      scrollRef.current.style.transition = 'all .5s'; 
    } else {
      scrollRef.current.style.opacity = 1;
      scrollRef.current.style.transition = 'all .5s'; 
    }
  }

  useEffect(() => {
    window.addEventListener("scroll", onScroll);
    Events.scrollEvent.register('begin', function () {
      console.log("begin", arguments);
    });

    Events.scrollEvent.register('end', function () {
      console.log("end", arguments);
    });    
    return () => {
      window.removeEventListener("scroll", onScroll);
      Events.scrollEvent.remove('begin');
      Events.scrollEvent.remove('end');
    };
  }, [])

  return (
    <section className="main" id="main">
      <nav className="navbar navbar-expand-md navbar-light" ref={ scrollRef }>
        <a className="navbar-brand" href="#">
          <p className="logo"> Welcome To </p> 
          Dibr Studio
        </a>
        <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarToggler" aria-controls="navbarToggler" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbarToggler">
          <ul className="navbar-nav ml-auto">
            <li className="nav-item"><span className="line"></span></li>
            <li className="nav-item">
              <Link className="nav-link blur" to="services" spy={true} smooth={true} duration={1000}>
                {t('service')}
              </Link>
            </li>
            <li className="nav-item">
              <Link className="nav-link blur" to="contact" spy={true} smooth={true} duration={1000}>
                {t('contact')}
              </Link>
            </li>
            <li className="nav-item">
              <div className="nav-link" onChange={ changeLanguage }>
                <input type="radio" value="en" id="en" name="language" defaultChecked />         
                <label htmlFor="en" className="blur">EN  </label>
                { ` | ` } 
                <input type="radio" value="id" id="id" name="language" />
                <label htmlFor="id" className="blur">  ID</label>
              </div>
            </li>
            <li className="nav-item ig-icon">
              <a className="nav-link" href="https://instagram.com">
                <i className="fa fa-instagram"></i> 
                <span> Instagram </span> 
                </a>
            </li>
          </ul>
        </div>
      </nav>
      <div className="banner-title">
        <h2> { t('banner') } </h2>
      </div>
      <div className="scroll-button">
        <Link className="down-arrow" to="work" spy={true} smooth={true} duration={1000}>
          <span></span>
        </Link>
      </div>      
    </section>
  )
}
export default function Home() {

  return (
    <div className="container-fluid">
      <Header />
      <Banner />
      <Work />
      <Service />
      <Contact />
      <Footer />
    </div>
  )
}