import * as PIXI from 'pixi.js'
import { Sprite, Stage } from 'react-pixi-fiber';
import bg from './monumen.jpg';
import bgMap from './monumen-map.jpeg';
import React, { useEffect, useState, useRef } from 'react';

const OPTIONS = { 
  height: window.innerHeight,
  width: window.innerWidth
}
const bgTexture = PIXI.Texture.from(bg)
const overlayTexture = PIXI.Texture.from(bgMap)


// TASK: resize window
// TASK: optimize on mobile
//    touchmove event
//    new images for mobile

function Banner() {    
  let mouseRef = useRef(null);
  const [ filters, setFilters ] = useState([]);
  const [ size, setSize ] = useState(OPTIONS)  
  
  useEffect(() => {
    setFilters([  new PIXI.filters.DisplacementFilter(mouseRef.current) ])
  }, [])

  useEffect(() => {    
    const handleResize = () => {      
      setSize({ height: window.innerHeight, width: window.innerWidth })
    }
    const mouseMove = (e) => {        
      let x = ( window.innerWidth / 2 - e.clientX ) / 35;
      let y = ( window.innerHeight / 2 - e.clientY ) / 25;
      if (filters.length > 0 ) {        
        let filter = filters.slice()[0]
        filter.scale.x = x;
        filter.scale.y = y;
        setFilters( [filter] )
      }
    }
    window.addEventListener('resize', handleResize)
    window.addEventListener('mousemove', mouseMove)
    // window.addEventListener('load', () => {
    //   let filter = new PIXI.filters.DisplacementFilter(mouseRef.current);
    //   setFilters([ filter ])      
    // })

    return () => {
      window.removeEventListener('mousemove', mouseMove) 
      window.removeEventListener('resize', handleResize) 
    }
  })

  return (   
    <div id="background">
      <Stage options={ OPTIONS }  filters={ filters } >
          <Sprite texture={ bgTexture } height={ size.height }  width={ size.width } />
          <Sprite
            ref={ mouseRef }
            width={ size.width }
            height={ size.height }  
            texture={ overlayTexture } 
          />
      </Stage>
    </div>
  )
}


export default Banner;